changeSet.sql:

            create sequence reporting_metrics.account_metrics_seq minvalue 0 maxvalue 999999999999999999 increment by 1 start with 1
            cache 1 no cycle;        

			create table reporting_metrics.account_metrics
			(
				id bigint not null primary key,
			    account_identifier bigint not null,
			    total_emissions bigint,
			    quantity_surrendered bigint,
			    quantity_reversed_surrendered bigint,
			    surrender_balance bigint,
			    dynamic_compliance_status varchar(40),

			    constraint "account_metrics_account_identifier"
			        unique ("account_identifier")
			);

			comment on table reporting_metrics.account_metrics is 'Stores aggregated data for the account entity';
            comment on column reporting_metrics.account_metrics.account_identifier
                is 'The business identifier of the account';
            comment on column reporting_metrics.account_metrics.total_emissions
                is 'The total emissions of the account';    
            comment on column reporting_metrics.account_metrics.surrender_balance
                is 'The net surrenders minus the total emissions of the account';
            comment on column reporting_metrics.account_metrics.quantity_surrendered
                is 'The total quantity of surrenders originating from the account';
            comment on column reporting_metrics.account_metrics.quantity_reversed_surrendered
                is 'The total quantity from reversal of surrenders';
            comment on column reporting_metrics.account_metrics.dynamic_compliance_status
                is 'The dynamic compliance status of the account';  

            create index "account_metrics_compl_idx" on reporting_metrics.account_metrics ("dynamic_compliance_status");
            create index "account_metrics_surrender_bal_idx" on reporting_metrics.account_metrics ("surrender_balance");

            create sequence reporting_metrics.processed_account_metrics_event_seq minvalue 0 maxvalue 999999999999999999 increment by 1 start with 1
            cache 1 no cycle;

            create table reporting_metrics.processed_account_metrics_event
            (
	            id bigint not null primary key,
	            event_id uuid not null,
	            payload jsonb not null,
	            processed_on timestamp not null
            );

            comment on table reporting_metrics.processed_account_metrics_event is 'Stores the processed reporting metrics data entity';
            comment on column reporting_metrics.processed_account_metrics_event.event_id is 'The reporting metrics data event payload unique identifier.';
            comment on column reporting_metrics.processed_account_metrics_event.payload is 'The reporting metrics data event payload in json format';

            create index idx_processed_account_metrics_payload_gin on reporting_metrics.processed_account_metrics_event using gin(payload);
            create unique index "processed_account_metrics_event_event_id_uq_idx" on reporting_metrics.processed_account_metrics_event (event_id);

            create sequence reporting_metrics_outbox_seq minvalue 0 maxvalue 999999999999999999 increment by 1 start with 1
            cache 1 no cycle;

            create table reporting_metrics_outbox
            (
	            id bigint not null primary key,
	            event_id uuid not null,
	            payload jsonb not null,
	            generated_on timestamp not null,
	            status varchar(20) not null
            );

            comment on table reporting_metrics_outbox is 'Reporting metrics data outbox entity';
            comment on column reporting_metrics_outbox.event_id is 'The reporting metrics data event payload unique identifier.';
            comment on column reporting_metrics_outbox.payload is 'The reporting metrics data event payload in json format';
            comment on column reporting_metrics_outbox.status is 'The status can be either created or sent';

            create unique index "reporting_metrics_outbox_event_id_uq_idx" on reporting_metrics_outbox (event_id);
            create index idx_reporting_metrics_outbox_payload_gin  on reporting_metrics_outbox using gin(payload);
            create index "reporting_metrics_outbox_status_generated_on_idx" on reporting_metrics_outbox (status, generated_on);
